-- COURSES



-- MIXED CREDIT HOURS (3 / 4 / 8)
UPDATE courses
SET credits = CASE
  WHEN (CAST(SUBSTR(course_code, 4) AS INTEGER) % 10) = 0 THEN 8
  WHEN (CAST(SUBSTR(course_code, 4) AS INTEGER) % 3) = 0 THEN 4
  ELSE 3
END
WHERE course_code LIKE 'EDU%';

